{
  "name": "money-transfer-saga",
  "version": "1.0.0",
  "private": true,
  "type": "commonjs",
  "scripts": {
    "worker": "node -r ts-node/register src/worker.ts",
    "client": "node -r ts-node/register src/client.ts",
    "start": "bash -c 'node -r ts-node/register src/worker.ts & WORKER_PID=$!; node -r ts-node/register src/client.ts; kill $WORKER_PID'"
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.5",
    "@temporalio/client": "^1.11.5",
    "@temporalio/worker": "^1.11.5",
    "@temporalio/workflow": "^1.11.5"
  },
  "devDependencies": {
    "ts-node": "^10.9.2",
    "typescript": "^5.5.4"
  }
}

export interface MoneyTransferInput {
  fromAccount: string;
  toAccount: string;
  amount: number;
}

import { promises as fs } from "fs";

const ACCOUNTS_PATH = "/workspace/accounts.json";

type Accounts = Record<string, number>;

async function readAccounts(): Promise<Accounts> {
  const raw = await fs.readFile(ACCOUNTS_PATH, "utf8");
  return JSON.parse(raw) as Accounts;
}

async function writeAccounts(accounts: Accounts): Promise<void> {
  await fs.writeFile(ACCOUNTS_PATH, JSON.stringify(accounts, null, 2));
}

async function updateAccount(
  account: string,
  amountDelta: number
): Promise<void> {
  const accounts = await readAccounts();
  const current = accounts[account] ?? 0;
  accounts[account] = current + amountDelta;
  await writeAccounts(accounts);
}

export async function withdraw(account: string, amount: number): Promise<void> {
  await updateAccount(account, -amount);
}

export async function deposit(account: string, amount: number): Promise<void> {
  if (account === "B_FAIL") {
    throw new Error("Simulated deposit failure for B_FAIL");
  }
  await updateAccount(account, amount);
}

export async function refund(account: string, amount: number): Promise<void> {
  await updateAccount(account, amount);
}

import { proxyActivities } from "@temporalio/workflow";
import type { MoneyTransferInput } from "./types";
import type * as activities from "./activities";

const { withdraw, refund } = proxyActivities<typeof activities>({
  startToCloseTimeout: "10 seconds"
});

const { deposit } = proxyActivities<typeof activities>({
  startToCloseTimeout: "10 seconds",
  retry: {
    maximumAttempts: 2
  }
});

export async function MoneyTransfer(input: MoneyTransferInput): Promise<void> {
  const { fromAccount, toAccount, amount } = input;

  await withdraw(fromAccount, amount);

  try {
    await deposit(toAccount, amount);
  } catch (error) {
    await refund(fromAccount, amount);
    throw error;
  }
}

import { NativeConnection, Worker } from "@temporalio/worker";
import * as activities from "./activities";

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address || !apiKey || !namespace) {
    throw new Error("Missing Temporal Cloud environment variables");
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: "saga-ts",
    workflowsPath: require.resolve("./workflows"),
    activities
  });

  await worker.run();
}

run().catch((error) => {
  console.error("Worker failed", error);
  process.exit(1);
});

import { Client, Connection } from "@temporalio/client";
import type { MoneyTransferInput } from "./types";

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !apiKey || !namespace || !runId) {
    throw new Error("Missing required environment variables");
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey
  });

  const client = new Client({
    connection,
    namespace
  });

  const successInput: MoneyTransferInput = {
    fromAccount: "A",
    toAccount: "B",
    amount: 30
  };

  const successHandle = await client.workflow.start("MoneyTransfer", {
    taskQueue: "saga-ts",
    workflowId: `saga-ok-${runId}`,
    args: [successInput]
  });

  await successHandle.result();
  console.log("Success workflow completed");

  const failureInput: MoneyTransferInput = {
    fromAccount: "A",
    toAccount: "B_FAIL",
    amount: 50
  };

  const failureHandle = await client.workflow.start("MoneyTransfer", {
    taskQueue: "saga-ts",
    workflowId: `saga-fail-${runId}`,
    args: [failureInput]
  });

  try {
    await failureHandle.result();
    console.log("Failure workflow unexpectedly completed");
  } catch (error) {
    console.log("Failure workflow failed as expected");
  }

  console.log("Workflows finished");
}

run().catch((error) => {
  console.error("Client failed", error);
  process.exit(1);
});
